/* UserBookMapper.selectBookTotalAmount */
SELECT
	 FORMAT(SUM(CASE WHEN A.INOUT_TYPE = 'I' THEN A.AMOUNT ELSE 0 END), 0) AS incomeTotalAmount
	,FORMAT(SUM(CASE WHEN A.INOUT_TYPE = 'E' THEN A.AMOUNT ELSE 0 END), 0) AS expendituretotalamount
	,FORMAT(COUNT(1), 0) AS cnt
FROM
	TB_HOME_LEDGER_INFO A
LEFT JOIN
	TB_ACCOUNT_INFO B
ON
	A.MEMBER_ID = B.MEMBER_ID
AND
	A.AI_SEQ = B.AI_SEQ
WHERE
	A.MEMBER_ID = #{userId}
AND
	A.DEL_YN = 'N'

	AND A.TRAN_DATE BETWEEN #{beginDe} AND #{endDe}


	AND A.INOUT_TYPE = #{inoutType}


	AND A.OVER_SPENDING_YN = #{osYn}


	AND B.AI_SE = #{aiSe}


	AND A.AI_SEQ = #{aiSeq}

/* UserBookMapper.selectBookTotalCount */
SELECT
	COUNT(1)
FROM
	TB_HOME_LEDGER_INFO A
LEFT JOIN
	TB_ACCOUNT_INFO B
ON
	A.MEMBER_ID = B.MEMBER_ID
AND
	A.AI_SEQ = B.AI_SEQ
WHERE
	A.MEMBER_ID = #{userId}
AND
	A.DEL_YN = 'N'

	AND A.TRAN_DATE BETWEEN #{beginDe} AND #{endDe}


	AND A.INOUT_TYPE = #{inoutType}


	AND A.OVER_SPENDING_YN = #{osYn}


	AND B.AI_SE = #{aiSe}


	AND A.AI_SEQ = #{aiSeq}

/* UserBookMapper.selectBookList */ SELECT A.AI_SEQ AS aiSeq ,A.HLI_SEQ AS hliSeq ,A.CATEGORY_CODE AS categoryCode ,A.CI_SEQ AS ciSeq ,FORMAT(A.AMOUNT, 0) AS amount ,A.TRAN_DATE AS tranDate ,A.OVER_SPENDING_YN AS overSpendingYn ,A.REMARK AS remark ,DATE_FORMAT(A.REG_DT, '%Y-%m-%d') AS regDt ,B.AI_NM AS aiNm ,CASE WHEN A.INOUT_TYPE = 'I' THEN '수입' ELSE '지출' END AS inoutType ,CASE WHEN B.AI_SE = 'B' THEN '통장' ELSE '카드' END AS aiSe ,CASE WHEN B.AI_SE = 'B' THEN (SELECT BK.BANK_NAME FROM BANK_CODE BK WHERE BK.BANK_CODE = B.AI_CODE) ELSE (SELECT CC.CARD_NAME FROM CARD_CODE CC WHERE CC.CARD_CODE = B.AI_CODE) END AS aiCode ,CASE WHEN B.AI_SE = 'B' THEN '통장' WHEN B.CARD_TYPE = 'C' THEN '신용' ELSE '체크' END AS cardType FROM TB_HOME_LEDGER_INFO A LEFT JOIN TB_ACCOUNT_INFO B ON A.MEMBER_ID = B.MEMBER_ID AND A.AI_SEQ = B.AI_SEQ WHERE A.MEMBER_ID = #{userId} AND A.DEL_YN = 'N'
AND A.TRAN_DATE BETWEEN #{beginDe} AND #{endDe}
AND A.INOUT_TYPE = #{inoutType}
AND A.OVER_SPENDING_YN = #{osYn}
AND B.AI_SE = #{aiSe}
AND A.AI_SEQ = #{aiSeq}
ORDER BY A.TRAN_DATE DESC

/* UserBookMapper.selectBookSeq */
SELECT
	IFNULL(MAX(HLI_SEQ), 0) + 1
FROM
	TB_HOME_LEDGER_INFO
WHERE
	MEMBER_ID = #{userId}
AND
	AI_SEQ = #{aiSeq}

mapper.insert:
/* UserBookMapper.insertBook */
INSERT INTO TB_HOME_LEDGER_INFO (
	 MEMBER_ID
	,AI_SEQ
	,HLI_SEQ
	,CATEGORY_CODE
	,CI_SEQ
	,INOUT_TYPE
	,AMOUNT
	,TRAN_DATE
	,OVER_SPENDING_YN
	,REMARK
	,DEL_YN
	,REG_ID
	,REG_DT
	,UPD_ID
	,UPD_DT
) VALUES (
	 #{userId}
	,#{aiSeq}
	,#{hliSeq}
	,#{categoryCode}
	,#{ciSeq}
	,#{inoutType}
	,REPLACE(#{amount}, ',', '')
	,#{tranDate}
	,#{overSpendingYn}
	,#{remark}
	,'N'
	,#{userId}
	,now()
	,#{userId}
	,now()
)

mapper.update:
/* UserBookMapper.updateBook */
UPDATE
	TB_HOME_LEDGER_INFO
SET
	 CI_SEQ 			= #{ciSeq}
	,INOUT_TYPE 		= #{inoutType}
	,AMOUNT 			= REPLACE(#{amount}, ',', '')
	,TRAN_DATE 			= #{tranDate}
	,OVER_SPENDING_YN	= #{overSpendingYn}
	,REMARK 			= #{remark}
	,UPD_ID 			= #{userId}
	,UPD_DT				= now()
WHERE
	MEMBER_ID = #{userId}
AND
	AI_SEQ = #{aiSeq}
AND
	HLI_SEQ = #{hliSeq}

/* UserBookMapper.updateOverSpendingYn */
UPDATE
	TB_HOME_LEDGER_INFO
SET
	 OVER_SPENDING_YN 		= #{overSpendingYn}
	,UPD_ID 				= #{userId}
	,UPD_DT					= now()
WHERE
	MEMBER_ID = #{userId}
AND
	AI_SEQ = #{aiSeq}
AND
	HLI_SEQ = #{hliSeq}

/* UserBookMapper.deleteBook */
UPDATE
	TB_HOME_LEDGER_INFO
SET
	 DEL_YN 		= 'Y'
	,UPD_ID 		= #{userId}
	,UPD_DT			= now()
WHERE
	MEMBER_ID = #{userId}
AND
	AI_SEQ = #{aiSeq}
AND
	HLI_SEQ = #{hliSeq}

